// This is the entry point of the React application
import React from 'react';
import ReactDOM from 'react-dom';
import App from './App';

ReactDOM.render(<App />, document.getElementById('root'));

import React from 'react';
import './styles.css';

function App() {
  return (
    <div className="App">
      <h1>Welcome to My React App</h1>
      <p>This is a sample React application.</p>
    </div>
  );
}

export default App;

/* Styles for the React App */

.App {
  text-align: center;
}

h1 {
  font-size: 24px;
  color: #333;
}

p {
  font-size: 16px;
  color: #666;
}

import React from 'react';

function Header() {
  return (
    <header>
      <h2>This is the Header component</h2>
      <nav>
        <ul>
          <li><a href="/">Home</a></li>
          <li><a href="/about">About</a></li>
          <li><a href="/contact">Contact</a></li>
        </ul>
      </nav>
    </header>
  );
}

export default Header;

import React from 'react';

function Footer() {
  return (
    <footer>
      <p>This is the Footer component</p>
      <p>&copy; 2021 My React App. All rights reserved.</p>
    </footer>
  );
}

export default Footer;

import React from 'react';

function Home() {
  return (
    <div>
      <h2>Welcome to the Home component</h2>
      <p>This is the home page of the React app.</p>
    </div>
  );
}

export default Home;

import React from 'react';

function About() {
  return (
    <div>
      <h2>About Us</h2>
      <p>This is the About component.</p>
    </div>
  );
}

export default About;

import React from 'react';

function Contact() {
  return (
    <div>
      <h2>Contact Us</h2>
      <p>This is the Contact component.</p>
    </div>
  );
}

export default Contact;

/* Global styles */

body {
  background-color: #f2f2f2;
  font-family: Arial, sans-serif;
}

/* Header styles */

header {
  background-color: #333;
  padding: 10px;
  color: #fff;
}

header h2 {
  font-size: 20px;
  margin: 0;
}

header nav ul {
  list-style-type: none;
  margin: 0;
  padding: 0;
}

header nav ul li {
  display: inline-block;
  margin-right: 10px;
}

header nav ul li a {
  color: #fff;
  text-decoration: none;
}

/* Footer styles */

footer {
  background-color: #333;
  padding: 10px;
  color: #fff;
  text-align: center;
}

footer p {
  margin: 0;
}

/* Main content styles */

main {
  padding: 20px;
}

main h2 {
  font-size: 24px;
  margin: 0 0 10px;
}

main p {
  font-size: 16px;
  line-height: 1.5;
}

/* Utility classes */

.text-center {
  text-align: center;
}

.text-primary {
  color: #007bff;
}

.text-secondary {
  color: #6c757d;
}

.bg-primary {
  background-color: #007bff;
  color: #fff;
}

.bg-secondary {
  background-color: #6c757d;
  color: #fff;
}
